gRL(){return"\u0646\u06d5\u062a\u0648\u0627\u0646\u0631\u0627 \u06af\u06d5\u0634\u062a\u06d5\u06a9\u06d5 \u062a\u06c6\u0645\u0627\u0631 \u0628\u06a9\u0631\u06ce\u062a. \u062f\u0648\u0648\u0628\u0627\u0631\u06d5 \u0647\u06d5\u0648\u06b5 \u0628\u062f\u06d5\u0631\u06d5\u0648\u06d5."},
gRQ(){return"\u0646\u06d5\u062a\u0648\u0627\u0646\u0631\u0627 \u0626\u06d5\u0645 \u06af\u06d5\u0634\u062a\u06d5 \u0647\u06d5\u06b5\u0628\u0648\u06d5\u0634\u06ce\u0646\u0631\u06ce\u062a\u06d5\u0648\u06d5 \u2014 \u062a\u06a9\u0627\u06cc\u06d5 \u067e\u06d5\u06cc\u0648\u06d5\u0646\u062f\u06cc \u0628\u06d5 \u06a9\u06c6\u0645\u067e\u0627\u0646\u06cc\u0627\u06a9\u06d5 \u0628\u06a9\u06d5."},
gVS(){return"\u0646\u06d5\u062a\u0648\u0627\u0646\u0631\u0627 \u062f\u0627\u062a\u0627\u06a9\u0627\u0646 \u0628\u0627\u0631 \u0628\u06a9\u0631\u06ce\u0646"},
gVR(){return"\u067e\u06d5\u06cc\u0648\u06d5\u0646\u062f\u06cc \u0626\u06cc\u0646\u062a\u06d5\u0631\u0646\u06ce\u062a\u06d5\u06a9\u06d5\u062a \u0628\u067e\u0634\u06a9\u0646\u06d5 \u0648 \u062f\u0648\u0648\u0628\u0627\u0631\u06d5 \u0647\u06d5\u0648\u06b5 \u0628\u062f\u06d5\u0631\u06d5\u0648\u06d5."},
gYX(){return"\u062f\u0648\u0648\u0628\u0627\u0631\u06d5 \u0647\u06d5\u0648\u06b5 \u0628\u062f\u06d5\u0631\u06d5\u0648\u06d5"},
gRk(){return"\u062a\u06c6\u0645\u0627\u0631\u06a9\u0631\u062f\u0646\u06cc \u06a9\u06c6\u0645\u067e\u0627\u0646\u06cc\u0627"},
gRj(){return"\u0647\u06d5\u0698\u0645\u0627\u0631\u06ce\u06a9 \u062f\u0631\u0648\u0633\u062a \u0628\u06a9\u06d5 \u0628\u06c6 \u0628\u06b5\u0627\u0648\u06a9\u0631\u062f\u0646\u06d5\u0648\u06d5\u06cc \u06af\u06d5\u0634\u062a\u06d5\u06a9\u0627\u0646\u06cc \u0639\u0648\u0645\u0631\u06d5\u062a."},
gF7(){return"\u062a\u06c6\u0645\u0627\u0631\u06a9\u0631\u062f\u0646\u06cc \u06a9\u06c6\u0645\u067e\u0627\u0646\u06cc\u0627"},
gRi(){return"\u06a9\u06c6\u0645\u067e\u0627\u0646\u06cc\u0627\u06cc \u0646\u0648\u06ce\u06cc\u062a\u061f"},
gQY(){return"\u0646\u0627\u0648\u06cc \u06a9\u06c6\u0645\u067e\u0627\u0646\u06cc\u0627"},
