gQU(){return"\u0648\u06d5\u0633\u0641\u06ce\u06a9\u06cc \u06a9\u0648\u0631\u062a \u06a9\u06d5 \u0628\u06c6 \u06af\u06d5\u0634\u062a\u06cc\u0627\u0631\u0627\u0646 \u062f\u06d5\u0631\u062f\u06d5\u06a9\u06d5\u0648\u06ce\u062a"},
